from enum import Enum
from plum import dispatch
from typing import TypeVar, Union, Generic, List, Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

GenerateCallbackType = CFUNCTYPE(None, c_void_p)  

class IPdfSignatureAppearance(SpireObject):
    """Provide a custom signature appearance interface"""
    @dispatch
    def __init__(self):
        super(IPdfSignatureAppearance, self).__init__()
        self.callback_ptr = None

    def _generate_wrapper(self, canvas_ptr):
        canvas = PdfCanvas(canvas_ptr)  
        self.Generate(canvas)  

    def register_callback(self):
        self.callback_ptr = GenerateCallbackType(self._generate_wrapper)
        return self.callback_ptr

    def Generate(self, g: 'PdfCanvas'):
        pass